const testUser = "testuser"

// TestRegression demonstrates the multi-device U2F authentication bug where
// only the first registered U2F device receives a challenge during login.
func TestRegression(t *testing.T) {
	t.Run("MultiDeviceU2FChallenge", testMultiDeviceU2FChallenge)
	t.Run("MultiDeviceU2FDeviceManagement", testMultiDeviceU2FDeviceManagement)
	t.Run("U2FChallengeForMultipleRegisteredDevices", testU2FChallengeForMultipleDevices)
}

// testMultiDeviceU2FChallenge tests that when a user has multiple U2F devices,
// challenges are created for all of them, not just the first one.
func testMultiDeviceU2FChallenge(t *testing.T) {
	ctx := context.Background()

	// Create test auth server with in-memory backend
	authServer, backendSvc := newTestAuthServer(t)
	defer backendSvc.Close()

	// Register a test user
	if err := createTestUser(t, authServer, testUser); err != nil {
		t.Fatalf("Failed to create test user: %v", err)
	}

	// Create first U2F device
	device1 := createTestU2FDevice(t, "device1", 1)
	if err := authServer.UpsertMFADevice(ctx, testUser, device1); err != nil {
		t.Fatalf("Failed to register first device: %v", err)
	}

	// Create second U2F device
	device2 := createTestU2FDevice(t, "device2", 2)
	if err := authServer.UpsertMFADevice(ctx, testUser, device2); err != nil {
		t.Fatalf("Failed to register second device: %v", err)
	}

	// Create third U2F device
	device3 := createTestU2FDevice(t, "device3", 3)
	if err := authServer.UpsertMFADevice(ctx, testUser, device3); err != nil {
		t.Fatalf("Failed to register third device: %v", err)
	}

	// Verify all devices are registered
	devices, err := authServer.GetMFADevices(ctx, testUser)
	if err != nil {
		t.Fatalf("Failed to get MFA devices: %v", err)
	}
	if len(devices) != 3 {
		t.Errorf("Expected 3 devices, got %d", len(devices))
	}

	// Test mfaAuthChallenge - should create challenges for all U2F devices
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(authServer)
	if err != nil {
		t.Fatalf("Failed to create U2F storage: %v", err)
	}

	// Call mfaAuthChallenge to get challenges for all devices
	// This is the proper way to handle multiple devices
	challenge, err := authServer.(*auth.Server).MFAAuthChallenge(ctx, testUser, u2fStorage)
	if err != nil {
		t.Logf("Note: MFAAuthChallenge not directly accessible, skipping this check")
	} else {
		// The challenge should contain entries for all 3 U2F devices
		u2fChallenges := challenge.U2F
		if len(u2fChallenges) != 3 {
			t.Errorf("REGRESSION: Expected 3 U2F challenges for 3 devices, got %d", len(u2fChallenges))
		} else {
			t.Logf("PASS: mfaAuthChallenge properly creates %d challenges for %d devices", len(u2fChallenges), len(devices))
		}
	}

	// Test U2FSignRequest - this is where the bug likely is
	// It should return challenges for all devices, but likely only returns first
	t.Logf("Testing U2FSignRequest with multiple devices...")

	// First, we need to set up password authentication for the user
	password := []byte("password123")
	if err := updateUserPassword(t, authServer, testUser, password); err != nil {
		t.Fatalf("Failed to set user password: %v", err)
	}

	// Try to get U2F sign request
	// The bug: this will only return a challenge for the FIRST device
	signReq, err := authServer.U2FSignRequest(testUser, password)
	if err != nil {
		t.Logf("U2FSignRequest error (may indicate single-device limitation): %v", err)
	}

	if signReq != nil {
		// Check which device's KeyHandle we got
		keyHandles := []string{}
		for _, dev := range devices {
			u2fDev := dev.GetU2F()
			if u2fDev != nil {
				kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
				keyHandles = append(keyHandles, kh)
			}
		}

		// The sign request should contain challenges for all devices
		// But due to the bug, it likely only contains the first device
		if len(keyHandles) > 1 {
			// We have multiple devices - check if U2FSignRequest returns only one
			// The API is limited and can only return a single challenge
			// This is the core of the bug!
			t.Errorf("REGRESSION: U2FSignRequest returns single challenge (%q), but user has %d U2F devices",
				signReq.KeyHandle, len(keyHandles))
			t.Logf("U2F devices registered: %v", keyHandles)
			t.Logf("Challenge received for: %q", signReq.KeyHandle)
		}
	}
}

