)

const testUser = "testuser"

// TestRegression demonstrates the multi-device U2F authentication bug where
// only the first registered U2F device receives a challenge during login.
func TestRegression(t *testing.T) {
	t.Run("MultiDeviceU2FChallenge", testMultiDeviceU2FChallenge)
	t.Run("MultiDeviceU2FDeviceManagement", testMultiDeviceU2FDeviceManagement)
	t.Run("U2FChallengeForMultipleRegisteredDevices", testU2FChallengeForMultipleDevices)
}

// testMultiDeviceU2FChallenge tests that when a user has multiple U2F devices,
// challenges are created for all of them, not just the first one.
// This test fails on the current (buggy) code.
func testMultiDeviceU2FChallenge(t *testing.T) {
	ctx := context.Background()

	// Create test auth server with in-memory backend
	authServer, backendSvc := newTestAuthServer(t)
	defer backendSvc.Close()

	// Register a test user
	if err := createTestUser(t, authServer, testUser); err != nil {
		t.Fatalf("Failed to create test user: %v", err)
	}

	// Create first U2F device
	device1 := createTestU2FDevice(t, "device1", 1)
	if err := authServer.UpsertMFADevice(ctx, testUser, device1); err != nil {
		t.Fatalf("Failed to register first device: %v", err)
	}

	// Create second U2F device
	device2 := createTestU2FDevice(t, "device2", 2)
	if err := authServer.UpsertMFADevice(ctx, testUser, device2); err != nil {
		t.Fatalf("Failed to register second device: %v", err)
	}

	// Create third U2F device
	device3 := createTestU2FDevice(t, "device3", 3)
	if err := authServer.UpsertMFADevice(ctx, testUser, device3); err != nil {
		t.Fatalf("Failed to register third device: %v", err)
	}

	// Verify all devices are registered
	devices, err := authServer.GetMFADevices(ctx, testUser)
	if err != nil {
		t.Fatalf("Failed to get MFA devices: %v", err)
	}
	if len(devices) != 3 {
		t.Errorf("Expected 3 devices, got %d", len(devices))
		return
	}
	t.Logf("Successfully registered 3 U2F devices")

	// Create U2F authentication storage
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(authServer)
	if err != nil {
		t.Fatalf("Failed to create U2F storage: %v", err)
	}

	// Get U2F configuration
	authPref, err := authServer.GetAuthPreference()
	if err != nil {
		t.Fatalf("Failed to get auth preference: %v", err)
	}
	u2fConfig, err := authPref.GetU2F()
	if err != nil {
		t.Fatalf("Failed to get U2F config: %v", err)
	}

	// Test: Create individual challenges for each device
	// These should all be created successfully
	var challengesByDevice []*u2f.AuthenticateChallenge
	for i, device := range devices {
		if device.GetU2F() == nil {
			continue
		}
		challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
			Dev:        device,
			AppConfig:  *u2fConfig,
			StorageKey: testUser,
			Storage:    u2fStorage,
		})
		if err != nil {
			t.Fatalf("Failed to create challenge for device %d: %v", i, err)
		}
		challengesByDevice = append(challengesByDevice, challenge)
		t.Logf("Challenge %d created with KeyHandle: %q", i+1, challenge.KeyHandle)
	}

	if len(challengesByDevice) != 3 {
		t.Errorf("REGRESSION BUG: Expected 3 challenges created, got %d", len(challengesByDevice))
	}

	// Test: Verify each device gets a unique challenge
	keyHandleSet := make(map[string]bool)
	for i, challenge := range challengesByDevice {
		if keyHandleSet[challenge.KeyHandle] {
			t.Errorf("REGRESSION BUG: Duplicate KeyHandle detected: %q", challenge.KeyHandle)
		}
		keyHandleSet[challenge.KeyHandle] = true
		t.Logf("Challenge %d has unique KeyHandle", i+1)
	}

	if len(keyHandleSet) != 3 {
		t.Errorf("REGRESSION BUG: Expected 3 unique KeyHandles, got %d", len(keyHandleSet))
	}

	// Test: Try the old U2FSignRequest API that only returns a single challenge
	// This should demonstrate the limitation
	password := []byte("testpassword123")
	if err := setTestUserPassword(t, authServer, testUser, password); err != nil {
		t.Logf("Note: Could not set password for test user: %v", err)
		return
	}

	// Call U2FSignRequest - this should only return first device due to bug
	signReq, err := authServer.U2FSignRequest(testUser, password)
	if err != nil {
		t.Logf("U2FSignRequest returned error: %v", err)
		t.Logf("This may indicate the single-device limitation")
		return
	}

	if signReq == nil {
		t.Logf("U2FSignRequest returned nil, may indicate it only works with password auth")
		return
	}

	// Get the KeyHandles of all registered devices
	registeredKeyHandles := make([]string, 0)
	for _, device := range devices {
		u2fDev := device.GetU2F()
		if u2fDev != nil {
			kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
			registeredKeyHandles = append(registeredKeyHandles, kh)
		}
	}

	// The bug: U2FSignRequest only returns challenge for first device
	t.Logf("U2FSignRequest returned challenge for device: %q", signReq.KeyHandle)
	t.Logf("All registered devices: %v", registeredKeyHandles)

	if len(registeredKeyHandles) > 1 && signReq.KeyHandle == registeredKeyHandles[0] {
		t.Logf("BUG CONFIRMED: U2FSignRequest only returned first device (%q) out of %d devices",
			signReq.KeyHandle, len(registeredKeyHandles))
		t.Errorf("REGRESSION: When user has multiple U2F devices, U2FSignRequest returns challenge for only the first device")
	}
}

